import React, { useEffect, useState } from "react";
import Repository from "./Repository";
import "./Repositories.css";

export default function RepositoriesPage() {
  const [repos, setRepos] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    async function fetchRepos() {
      // ===============================
      // MODALITÀ REALE (commentata per evitare 403)
      // const fetchedRepos = await Repository.fetchAllByUsername("unix69");
      // setRepos(fetchedRepos);
      // ===============================

      // MODALITÀ SIMULATA
      const mockRepos = [
        new Repository({
          id: "1",
          name: "ReactApp",
          full_name: "unix69/ReactApp",
          stars: 25,
          forks: 10,
          open_issues_count: 3,
          clone_url: "https://github.com/unix69/ReactApp.git",
          owner: { login: "unix69", html_url: "https://github.com/unix69", avatar_url: "" },
          created_at: "2023-01-01T00:00:00Z",
          updated_at: "2023-03-01T12:00:00Z",
          description: "Una demo di app React"
        }),
        new Repository({
          id: "2",
          name: "NodeAPI",
          full_name: "unix69/NodeAPI",
          stars: 15,
          forks: 5,
          open_issues_count: 2,
          clone_url: "https://github.com/unix69/NodeAPI.git",
          owner: { login: "unix69", html_url: "https://github.com/unix69", avatar_url: "" },
          created_at: "2023-02-01T00:00:00Z",
          updated_at: "2023-03-10T12:00:00Z",
          description: "API in Node.js"
        }),
        new Repository({
          id: "3",
          name: "Portfolio",
          full_name: "unix69/Portfolio",
          stars: 40,
          forks: 12,
          open_issues_count: 0,
          clone_url: "https://github.com/unix69/Portfolio.git",
          owner: { login: "unix69", html_url: "https://github.com/unix69", avatar_url: "" },
          created_at: "2022-12-01T00:00:00Z",
          updated_at: "2023-02-15T12:00:00Z",
          description: "Portfolio personale"
        })
      ];

      // Lingue simulate
      mockRepos[0].languages = ["JavaScript", "HTML", "CSS"];
      mockRepos[1].languages = ["Node.js", "JavaScript"];
      mockRepos[2].languages = ["HTML", "CSS"];

      setRepos(mockRepos);
      setLoading(false);
    }

    fetchRepos();
  }, []);

  return (
    <main className="repositories-page">
      <h1>Repositories Overview</h1>

      <section className="intro-section">
        <p>
          Modalità simulata: puoi vedere le repository, le card e le statistiche senza fare fetch reale da GitHub.
        </p>
      </section>

      {loading && <p style={{ textAlign: "center" }}>Caricamento repository...</p>}

      {!loading && repos.length > 0 && (
        <section className="repos-list">
          {repos.map(repo => (
            <div key={repo.id} className="repo-card">
              <div className="repo-header">
                <strong>{repo.name}</strong> ({repo.visibility})
              </div>
              {repo.description && <p>{repo.description}</p>}
              <div className="repo-stats">
                ⭐ {repo.stars} | 🍴 {repo.forks} | 🐛 {repo.openIssues} | 🔀 {repo.pullRequests}
              </div>
              {repo.languages.length > 0 && (
                <div className="repo-languages">
                  {repo.languages.map(lang => (
                    <span key={lang} className="repo-language">{lang}</span>
                  ))}
                </div>
              )}
              <div className="repo-actions">
                <button onClick={() => repo.copyGitClone()}>Copy git clone</button>
                {repo.documentationLink && <a href={repo.documentationLink} target="_blank" rel="noopener noreferrer">Wiki / Docs</a>}
                {repo.liveDemoLink && <a href={repo.liveDemoLink} target="_blank" rel="noopener noreferrer">Live Demo</a>}
              </div>
            </div>
          ))}
        </section>
      )}

      {!loading && repos.length === 0 && (
        <p style={{ textAlign: "center" }}>Nessuna repository trovata.</p>
      )}
    </main>
  );
}
